.vm-listpagebody .pf-v6-c-table {
  .pf-v6-c-table__th.pf-v6-c-table__check {
    width: 50px !important;
    max-width: 50px;
  }

  .selection-column {
    width: 50px;
    max-width: 50px;
  }
}

.vm-list-page-header {
  h1.co-m-pane__heading {
    font-size: var(--pf-t--global--font--size--lg);
  }
}
